import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface HeartRateData {
  currentHeartRate: number;
  restingHeartRate: number;
  trend24h: number[];
}

export default function Widget() {
  const heartRateData = response.data.data as HeartRateData;
  const { currentHeartRate, restingHeartRate, trend24h } = heartRateData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#333' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5252', mb: 1 }}>
              Heart Rate Monitor
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 0.5 }}>
              Current Heart Rate
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FFC107' }}>
              {currentHeartRate} bpm
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mt: 0.5 }}>
              Resting Heart Rate: {restingHeartRate} bpm
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: trend24h,
                  color: '#FF5252',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'linear',
                  data: trend24h.map((_, index) => index),
                  id: 'time',
                },
              ]}
              yAxis={[{ id: 'bpm' }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="time"
                tickLabelStyle={{ fontSize: 10, fill: '#FFF' }}
              />
              <ChartsYAxis
                axisId="bpm"
                tickLabelStyle={{ fontSize: 10, fill: '#FFF' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
